-- Migration 0028: seed de receitas Sul (gerado por scripts/generate-recipes-seed.mjs)
-- 22 receitas curadas para region='sul'. UPSERT por slug.

delete from public.recipes where region = 'sul';

on conflict (slug) do update set
  title = excluded.title,
  icon = excluded.icon,
  category = excluded.category,
  time_label = excluded.time_label,
  description = excluded.description,
  region = excluded.region,
  state = excluded.state,
  data = excluded.data;
